// Time:  O(c + n + q), n = len(connections)
// Space: O(c + n)

// dfs, flood fill, sort
class Solution {
public:
    vector<int> processQueries(int c, vector<vector<int>>& connections, vector<vector<int>>& queries) {
        vector<vector<int>> adj(c);
        for (const auto& c : connections) {
            adj[c[0] - 1].emplace_back(c[1] - 1);
            adj[c[1] - 1].emplace_back(c[0] - 1);
        }
        vector<int> lookup(c, -1);
        const auto& iter_dfs = [&](int i) {
            vector<int> stk = {i};
            while (!empty(stk)) {
                const auto u = stk.back(); stk.pop_back();
                if (lookup[u] != -1) {
                    continue;
                }
                lookup[u] = i;
                for (const auto& v : adj[u]) {
                    stk.emplace_back(v);
                }
            }
        };

        for (int i = 0; i < c; ++i) {
            iter_dfs(i);
        }
        vector<vector<int>> groups(c);
        for (int i = c - 1; i >= 0; --i) {
            groups[lookup[i]].emplace_back(i);
        }
        vector<int> result;
        vector<bool> online(c, true);
        for (const auto& q : queries) {
            const auto t = q[0], x = q[1] - 1;
            if (t == 1) {
                if (online[x]) {
                    result.emplace_back(x + 1);
                    continue;
                }
                while (!empty(groups[lookup[x]]) && !online[groups[lookup[x]].back()]) {
                    groups[lookup[x]].pop_back();
                }
                result.emplace_back(!empty(groups[lookup[x]]) ? groups[lookup[x]].back() + 1 : -1);
            } else {
                online[x] = false;
            }
        }
        return result;
    }
};

# Time:  O(c + n + q), n = len(connections)
# Space: O(c + n)

# dfs, flood fill, sort
class Solution(object):
    def processQueries(self, c, connections, queries):
        """
        :type c: int
        :type connections: List[List[int]]
        :type queries: List[List[int]]
        :rtype: List[int]
        """
        def iter_dfs(i):
            stk = [i]
            while stk:
                u = stk.pop()
                if lookup[u] != -1:
                    continue
                lookup[u] = i
                for v in reversed(adj[u]):
                    stk.append(v)

        adj = [[] for _ in xrange(c)]
        for u, v in connections:
            adj[u-1].append(v-1)
            adj[v-1].append(u-1)
        lookup = [-1]*c
        for i in xrange(c):
            iter_dfs(i)
        groups = [[] for _ in xrange(c)]
        for i in reversed(xrange(c)):
            groups[lookup[i]].append(i)
        result = []
        online = [True]*c
        for t, x in queries:
            x -= 1
            if t == 1:
                if online[x]:
                    result.append(x+1)
                    continue
                while groups[lookup[x]] and not online[groups[lookup[x]][-1]]:
                    groups[lookup[x]].pop()
                result.append(groups[lookup[x]][-1]+1 if groups[lookup[x]] else -1)
            else:
                online[x] = False
        return result
